277→    /// Helper to build a `BranchDecision` with a numeric comparison constraint.
278→    fn numeric_branch(id: u32, taken: bool, op: BinOpKind, left: i64, right: i64) -> BranchDecision {
279→        BranchDecision {
280→            branch_id: id,
281→            line: id * 10,
282→            taken,
283→            constraint: SymConstraint::Expr {
284→                expr: SymExpr::BinOp {
