478→    #[test]
479→    fn fitness_always_in_zero_one_range() {
480→        let scenarios: Vec<Vec<BranchDecision>> = vec![
481→            vec![],
482→            vec![numeric_branch(1, true, BinOpKind::Gt, 100, 0)],
483→            vec![unknown_branch(1), unknown_branch(2), unknown_branch(3)],
484→            vec![
485→                numeric_branch(1, false, BinOpKind::Lt, 50, 10),
486→                numeric_branch(2, true, BinOpKind::Eq, 7, 7),
487→                unknown_branch(3),
488→            ],
489→        ];
490→        let targets: HashSet<u32> = [1, 2, 3, 4].into_iter().collect();
491→
492→        for (i, path) in scenarios.into_iter().enumerate() {
493→            let mut ctx = FitnessContext::new();
494→            let result = make_result(path);
495→            let b = score(&result, &targets, &mut ctx, &FitnessWeights::default());
496→            assert!(
497→                b.total >= 0.0 && b.total <= 1.0,
498→                "scenario {i}: total {:.4} out of range",
499→                b.total
500→            );
501→            assert!(b.coverage >= 0.0 && b.coverage <= 1.0);
502→            assert!(b.proximity >= 0.0 && b.proximity <= 1.0);
503→            assert!(b.unknown_bonus >= 0.0 && b.unknown_bonus <= 1.0);
504→            assert!(b.novelty >= 0.0 && b.novelty <= 1.0);
505→        }
506→    }
