508→    #[test]
509→    fn zero_weights_give_zero_total() {
510→        let result = make_result(vec![numeric_branch(1, true, BinOpKind::Eq, 5, 5)]);
511→        let targets: HashSet<u32> = [1].into_iter().collect();
512→        let mut ctx = FitnessContext::new();
513→        let weights = FitnessWeights {
514→            coverage: 0.0,
515→            proximity: 0.0,
516→            unknown_bonus: 0.0,
517→            novelty: 0.0,
518→        };
519→        let b = score(&result, &targets, &mut ctx, &weights);
520→        assert_eq!(b.total, 0.0);
521→    }
522→}
