 70→/// Generate a random JSON value matching the given type.
 71→///
 72→/// Uses biased distributions that favor boundary values (0, -1, 1, empty
 73→/// strings, etc.) to increase the chance of hitting interesting branches.
 74→///
 75→/// When `caps` is provided, complex types check whether the frontend declared
 76→/// support. Unsupported complex types fall back to `Unknown` generation.
 77→pub fn generate_random_value(
 78→    typ: &TypeInfo,
 79→    rng: &mut impl Rng,
 80→    caps: Option<&FrontendCapabilities>,
 81→) -> Value {
 82→    match typ {
 83→        TypeInfo::Int => generate_int(rng),
 84→        TypeInfo::Float => generate_float(rng),
 85→        TypeInfo::Str => generate_string(rng),
 86→        TypeInfo::Bool => json!(rng.random_bool(0.5)),
 87→        TypeInfo::Array { element } => generate_array(element, rng, caps),
 88→        TypeInfo::Object { fields } => generate_object(fields, rng, caps),
 89→        TypeInfo::Union { variants } => generate_union(variants, rng, caps),
 90→        TypeInfo::Nullable { inner } => generate_nullable(inner, rng, caps),
 91→        TypeInfo::Complex { kind, metadata, inner } => {
 92→            if caps.is_some_and(|c| c.supports_complex(*kind)) {
 93→                generate_complex_value(*kind, metadata, inner.as_deref(), rng)
 94→            } else {
 95→                generate_unknown(rng)
 96→            }
 97→        }
 98→        TypeInfo::Opaque { .. } => Value::Null,
 99→        TypeInfo::Unknown => generate_unknown(rng),
100→    }

200→    /// Number of inputs generated by parameter drilling on stalled frontiers.
