// -- Fitness-scored worklist ordering tests --

/// Entries with fitness scores outrank entries without, regardless of source.
#[test]
fn fitness_scored_entries_outrank_unscored() {
    let mut worklist = BinaryHeap::new();

    worklist.push(WorklistEntry {
        inputs: vec![serde_json::json!("z3")],
        source: InputSource::Z3Solved,
        fitness: None,
    });
    worklist.push(WorklistEntry {
        inputs: vec![serde_json::json!("seed_scored")],
        source: InputSource::Seed,
        fitness: Some(0.1),
    });

    let first = worklist.pop().expect("worklist should not be empty");
    assert!(
        first.fitness.is_some(),
        "scored entry should be popped before unscored Z3Solved"
    );
}

/// Among scored entries, higher fitness wins. Source is tiebreaker.
#[test]
fn higher_fitness_drains_first() {
    let mut worklist = BinaryHeap::new();

    worklist.push(WorklistEntry {
        inputs: vec![serde_json::json!("low")],
        source: InputSource::Z3Solved,
        fitness: Some(0.3),
    });
    worklist.push(WorklistEntry {
        inputs: vec![serde_json::json!("high")],
        source: InputSource::Seed,
        fitness: Some(0.9),
    });
    worklist.push(WorklistEntry {
        inputs: vec![serde_json::json!("mid")],
        source: InputSource::Fuzzed,
        fitness: Some(0.5),
    });

    let drained: Vec<(Option<f64>, InputSource)> = std::iter::from_fn(|| worklist.pop())
        .map(|e| (e.fitness, e.source))
        .collect();

    assert_eq!(drained[0].0, Some(0.9));
    assert_eq!(drained[1].0, Some(0.5));
    assert_eq!(drained[2].0, Some(0.3));
}

/// Same fitness score uses source as tiebreaker.
